                            </div>
                        )}
                    </div>
                </div>
            </main>

            {toast && <Toast message={toast.message} type={toast.type} />}
            <ModalsRenderer />
        </div>
    );
};

// --- App Controller ---
const AppController: React.FC = () => {
    const { session, loading } = useAuth();

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-[#051024]">
                <LoadingSpinner />
            </div>
        );
    }

    if (!session) {
        return <AuthView />;
    }

    return (
        <ErrorBoundary>
            <UIProvider>
                <AppProvider>
                    <MainAppContent />
                </AppProvider>
            </UIProvider>
        </ErrorBoundary>
    );
}

export default function App() {
    return (
        <I18nProvider>
            <AuthProvider>
                <AppController />
            </AuthProvider>
        </I18nProvider>
    );
}

